{"path": "/tmp/sv-d38dbd91ed20455bba8ac8520dc8cb91/Components/Chat/MessageBubble.razor", "file_text": "<div class="message-bubble p-2 rounded position-relative"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="d-flex justify-content-between align-items-start">
        <div>
            <strong>@Message.Author</strong>
            <small class="text-muted ms-2">@TimeHelper.RelativeTime(Message.SentAt)</small>
        </div>
        @if (_showActions)
        {
            <div class="message-actions d-flex gap-1">
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        @onclick="ToggleEmojiPicker" title="React">
                    😊
                </button>
                <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                        @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply">
                    💬
                </button>
            </div>
        }
    </div>
    <div class="mt-1">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <ReactionBar Reactions="Message.Reactions" OnReact="HandleReact" />
    }

    @if (ReplyCount > 0)
    {
        <button class="btn btn-sm btn-link text-primary p-0 mt-1"
                @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showEmojiPicker)
    {
        <div class="position-absolute" style="top: -8px; right: 0; z-index: 10;">
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleReact(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}
"}

