{"path": "/tmp/sv-d38dbd91ed20455bba8ac8520dc8cb91/Components/Chat/MessageInput.razor", "file_text": "<div class="d-flex gap-2 p-3 border-top bg-white">
    <textarea class="form-control" rows="1"
              placeholder="@Placeholder"
              @bind="_text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"></textarea>
    <button class="btn btn-primary align-self-end"
            @onclick="Send"
            disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string _text = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }

    private async Task Send()
    {
        var content = _text.Trim();
        if (string.IsNullOrEmpty(content)) return;
        _text = "";
        await OnSend.InvokeAsync(content);
    }
}
"}

{"path": "/tmp/sv-d38dbd91ed20455bba8ac8520dc8cb91/Components/Chat/MessageList.razor", "file_text": "<div class="d-flex flex-column h-100">
    <div class="flex-grow-1 overflow-auto p-3">
        @if (HasMore)
        {
            <div class="text-center mb-3">
                <button class="btn btn-sm btn-outline-secondary"
                        @onclick="OnLoadMore"
                        disabled="@IsLoading">
                    @(IsLoading ? "Loading…" : "Load older messages")
                </button>
            </div>
        }

        @foreach (var message in Messages)
        {
            <MessageBubble Message="message"
                           ReplyCount="GetReplyCount(message.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = new();
    [Parameter] public bool HasMore { get; set; } = true;
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ReplyCounts.TryGetValue(messageId, out var count) ? count : 0;
}
"}

{"path": "/tmp/sv-d38dbd91ed20455bba8ac8520dc8cb91/Components/Chat/ThreadPanel.razor", "file_text": "<div class="d-flex flex-column h-100 border-start bg-white">
    <div class="p-3 border-bottom d-flex justify-content-between align-items-center">
        <h6 class="mb-0 fw-bold">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="p-3 border-bottom bg-light">
            <strong>@RootMessage.Author</strong>
            <small class="text-muted ms-2">@TimeHelper.RelativeTime(RootMessage.SentAt)</small>
            <div class="mt-1">@RootMessage.Content</div>
            @if (RootMessage.Reactions.Count > 0)
            {
                <ReactionBar Reactions="RootMessage.Reactions"
                             OnReact="(emoji) => OnReactInThread.InvokeAsync((RootMessage.Id, emoji))" />
            }
        </div>

        <div class="flex-grow-1 overflow-auto p-3">
            @if (Replies.Count > 0)
            {
                <small class="text-muted d-block mb-2">@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</small>
            }
            @foreach (var reply in Replies)
            {
                <div class="mb-3">
                    <strong>@reply.Author</strong>
                    <small class="text-muted ms-2">@TimeHelper.RelativeTime(reply.SentAt)</small>
                    <div class="mt-1">@reply.Content</div>
                    @if (reply.Reactions.Count > 0)
                    {
                        <ReactionBar Reactions="reply.Reactions"
                                     OnReact="(emoji) => OnReactInThread.InvokeAsync((reply.Id, emoji))" />
                    }
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply…" ButtonText="Reply" OnSend="OnSendReply" />
    }
</div>

@code {
