arguments.file_text:
@page "/chat"
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-container d-flex">
    <!-- Channel Sidebar -->
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <!-- Main Message Area -->
    <div class="chat-main d-flex flex-column">
        @if (_currentChannel is not null)
        {
            <div class="p-3 border-bottom bg-white">
                <h5 class="mb-1"># @_currentChannel.Name</h5>
                <small class="text-muted">@_currentChannel.Description</small>
            </div>

            <div class="flex-grow-1 overflow-hidden">
                <MessageList Messages="_displayMessages"
                             ReplyCounts="_replyCounts"
                             HasMore="_hasMore"
                             IsLoading="_isLoadingMore"
                             OnLoadMore="LoadMoreMessages"
                             OnOpenThread="OpenThread"
                             OnReact="HandleReaction" />
            </div>

            <MessageInput OnSend="SendMessage" />
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center flex-grow-1 text-muted">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    <!-- Thread Panel -->
    @if (_isThreadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReactInThread="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private int? _selectedChannelId;
    private Channel? _currentChannel;

    private List<Message> _allMessages = new();
    private List<Message> _displayMessages = new();
    private Dictionary<int, int> _replyCounts = new();
    private bool _hasMore = true;
    private bool _isLoadingMore;
    private const int PageSize = 30;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = new();

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _hasMore = true;
        CloseThread();

        _allMessages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        UpdateDisplayMessages();

        await ChatService.MarkChannelReadAsync(channelId);
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _currentChannel! with { UnreadCount = 0 };
            _currentChannel = _channels[idx];
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || _selectedChannelId is null) return;
        _isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId.Value, _allMessages.Count, PageSize);

        if (older.Count < PageSize) _hasMore = false;
        _allMessages.AddRange(older);
        UpdateDisplayMessages();
        _isLoadingMore = false;
    }

    private void UpdateDisplayMessages()
    {
        _displayMessages = _allMessages
            .Where(m => m.ReplyToId is null)
            .OrderBy(m => m.SentAt)
            .ToList();

        _replyCounts = _allMessages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _allMessages.Add(msg);
        UpdateDisplayMessages();
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _allMessages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = new();
    }

    private async Task SendThreadReply(string content)
    {
        if (_selectedChannelId is null || _threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);
        _allMessages.Add(reply);
        UpdateDisplayMessages();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh current view to reflect updated reactions
        if (_selectedChannelId is not null)
        {
            _allMessages = await ChatService.GetMessagesAsync(
                _selectedChannelId.Value, 0, _allMessages.Count);
            UpdateDisplayMessages();
        }
        if (_isThreadOpen && _threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }
}

.chat-container {
    height: calc(100vh - 3.5rem);
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
}

.chat-thread {
    width: 25%;
    min-width: 250px;
    flex-shrink: 0;
}

@page "/chat"
